const express = require('express');
const cors = require('cors');

const app = express();
// Use the port from the .env file, or default to 5000
const PORT = process.env.PORT || 5000;

// Middleware
app.use(cors()); // Allows your React frontend to communicate with this backend
app.use(express.json()); // Allows Express to parse JSON bodies in POST requests

// Mock Database of 3D Printed Items
const products = [
  { id: 1, name: "Articulated Dragon", price: 25.00, category: "Toys", material: "PLA" },
  { id: 2, name: "Low-Poly Bulbasaur Planter", price: 15.00, category: "Gadgets", material: "PETG" },
  { id: 3, name: "Planetary Gear Fidget", price: 10.00, category: "Gadgets", material: "ABS" },
  { id: 4, name: "Flexi-Rex T-Rex", price: 12.00, category: "Toys", material: "TPU" },
  { id: 5, name: "Headphone Stand", price: 20.00, category: "Gadgets", material: "PLA" }
];

// --- ROUTES ---

// GET /api/products : Returns the list of available 3D prints
app.get('/api/products', (req, res) => {
  res.status(200).json(products);
});

// POST /api/checkout : Handles the shopping cart submission
app.post('/api/checkout', (req, res) => {
  const { cartItems } = req.body;
  
  if (!cartItems || cartItems.length === 0) {
    return res.status(400).json({ error: "Cart is empty." });
  }

  // Log the order to the console to simulate processing
  console.log("New order received for printing:");
  console.table(cartItems);
  
  // Respond to the frontend
  res.status(200).json({ 
    message: "Order placed successfully! The extruders are heating up." 
  });
});

// Start the server
app.listen(PORT, () => {
  console.log(`🚀 Backend server running on http://localhost:${PORT}`);
});